hooks.command:
node -e "
const p=process.env.TOOL_INPUT_FILE_PATH||'';
const fs=require('fs');
if(!p.endsWith('.py'))process.exit(0);
try{const c=fs.readFileSync(p,'utf8');
if(/frappe\.db\.sql\s*\(.*[fF]['"]/.test(c)||/frappe\.db\.sql\s*\(.*\.format\s*\(/.test(c)){
console.error('[Frappe Hook] CRITICAL: SQL injection risk in '+p+' — frappe.db.sql() with f-string or .format(). Use %(key)s with dict params.');}}catch(e){}
"

node -e "
const p=process.env.TOOL_INPUT_FILE_PATH||'';
const fs=require('fs');
try{const c=fs.readFileSync(p,'utf8');
if(c.match(/def\s+validate\s*\(/m)&&c.match(/frappe\.db\.commit\s*\(/)){
console.error('[Frappe Hook] CRITICAL: frappe.db.commit() inside validate() detected in '+p+' — remove it, Frappe manages transactions.');}}catch(e){}
"

node -e "
const p=process.env.TOOL_INPUT_FILE_PATH||'';
const fs=require('fs');
try{const c=fs.readFileSync(p,'utf8');
if(c.match(/for\s+\w+\s+in\s+/)&&c.match(/frappe\.get_doc\s*\(/)){
console.error('[Frappe Hook] HIGH: frappe.get_doc() inside a loop detected in '+p+' — use frappe.get_all(filters={name:[in,names]}) for bulk fetch.');}}catch(e){}
"

node -e "
const p=process.env.TOOL_INPUT_FILE_PATH||'';
